import pandas as pd
import numpy as np

df = pd.read_csv('AI_Student_Life_Pakistan_2026.csv')

impact_rank = {
    'Significant Decline': 1,
    'Slight Decline': 2,
    'No Change': 3,
    'Improved': 4,
    'Significantly Improved': 5
}

df = df.copy()
df['Impact_Score'] = df['Impact_on_Grades'].map(impact_rank)

# Compare students with very similar study/usage time by grouping into narrow bins
bin_width = 0.5
df['Usage_Bin_Start'] = (np.floor(df['Daily_Usage_Hours'] / bin_width) * bin_width).round(1)
df['Usage_Bin'] = df['Usage_Bin_Start'].astype(str) + '-' + (df['Usage_Bin_Start'] + bin_width).round(1).astype(str)

pairs = []
for usage_bin, group in df.groupby('Usage_Bin'):
    group = group.sort_values('Impact_Score')
    if len(group) < 2:
        continue
    min_score = group['Impact_Score'].min()
    max_score = group['Impact_Score'].max()
    if pd.notna(min_score) and pd.notna(max_score) and (max_score - min_score) >= 2:
        low_students = group[group['Impact_Score'] == min_score]
        high_students = group[group['Impact_Score'] == max_score]
        for _, low_row in low_students.iterrows():
            for _, high_row in high_students.iterrows():
                differing_factors = {}
                for col in ['Purpose', 'AI_Tool_Used', 'Satisfaction_Level', 'Education_Level', 'City', 'Gender', 'Age']:
                    if low_row[col] != high_row[col]:
                        differing_factors[col] = {
                            'lower_performance_student': low_row[col],
                            'higher_performance_student': high_row[col]
                        }
                pairs.append({
                    'usage_bin': usage_bin,
                    'lower_performance_student': {
                        'Student_ID': int(low_row['Student_ID']),
                        'Daily_Usage_Hours': float(low_row['Daily_Usage_Hours']),
                        'Impact_on_Grades': low_row['Impact_on_Grades'],
                        'Purpose': low_row['Purpose'],
                        'AI_Tool_Used': low_row['AI_Tool_Used'],
                        'Satisfaction_Level': low_row['Satisfaction_Level'],
                        'Education_Level': low_row['Education_Level'],
                        'City': low_row['City'],
                        'Gender': low_row['Gender'],
                        'Age': int(low_row['Age'])
                    },
                    'higher_performance_student': {
                        'Student_ID': int(high_row['Student_ID']),
                        'Daily_Usage_Hours': float(high_row['Daily_Usage_Hours']),
                        'Impact_on_Grades': high_row['Impact_on_Grades'],
                        'Purpose': high_row['Purpose'],
                        'AI_Tool_Used': high_row['AI_Tool_Used'],
                        'Satisfaction_Level': high_row['Satisfaction_Level'],
                        'Education_Level': high_row['Education_Level'],
                        'City': high_row['City'],
                        'Gender': high_row['Gender'],
                        'Age': int(high_row['Age'])
                    },
                    'possible_explanatory_factors': differing_factors
                })

# Summarize which factors most often differ across matched pairs
factor_counts = {}
for p in pairs:
    for factor in p['possible_explanatory_factors']:
        factor_counts[factor] = factor_counts.get(factor, 0) + 1

factor_counts = dict(sorted(factor_counts.items(), key=lambda x: (-x[1], x[0])))

result = {
    'matched_students_with_similar_study_time_but_different_performance': pairs,
    'most_common_possible_explanatory_factors': factor_counts,
    'interpretation': (
        "Students were matched within 0.5-hour Daily_Usage_Hours bins and flagged when their "
        "Impact_on_Grades differed substantially. Likely explanations come from differences in "
        "Purpose, AI_Tool_Used, Satisfaction_Level, Education_Level, City, Gender, and Age among "
        "students using AI for similar amounts of time."
    )
}

