import pandas as pd
import numpy as np

df = pd.read_csv('AI_Student_Life_Pakistan_2026.csv')

impact_order = {
    'Significant Decline': 0,
    'Slight Decline': 1,
    'No Change': 2,
    'Improved': 3,
    'Significantly Improved': 4
}

df = df.copy()
df['Impact_Score'] = df['Impact_on_Grades'].map(impact_order)

pairs = []
usage_values = sorted(df['Daily_Usage_Hours'].unique())

for usage in usage_values:
    group = df[df['Daily_Usage_Hours'] == usage].copy()
    if len(group) < 2:
        continue
    min_score = group['Impact_Score'].min()
    max_score = group['Impact_Score'].max()
    if pd.notna(min_score) and pd.notna(max_score) and (max_score - min_score) >= 2:
        low_students = group[group['Impact_Score'] == min_score]
        high_students = group[group['Impact_Score'] == max_score]
        for _, low_row in low_students.iterrows():
            for _, high_row in high_students.iterrows():
                differing_factors = {}
                for col in ['Education_Level', 'Purpose', 'AI_Tool_Used', 'Satisfaction_Level', 'Gender', 'City', 'Age']:
                    if low_row[col] != high_row[col]:
                        differing_factors[col] = [low_row[col], high_row[col]]
                pairs.append({
                    'Daily_Usage_Hours': float(usage),
                    'lower_performance_student': {
                        'Student_ID': int(low_row['Student_ID']),
                        'Impact_on_Grades': low_row['Impact_on_Grades'],
                        'Purpose': low_row['Purpose'],
                        'AI_Tool_Used': low_row['AI_Tool_Used'],
                        'Satisfaction_Level': low_row['Satisfaction_Level'],
                        'Education_Level': low_row['Education_Level'],
                        'City': low_row['City'],
                        'Gender': low_row['Gender'],
                        'Age': int(low_row['Age'])
                    },
                    'higher_performance_student': {
                        'Student_ID': int(high_row['Student_ID']),
                        'Impact_on_Grades': high_row['Impact_on_Grades'],
                        'Purpose': high_row['Purpose'],
                        'AI_Tool_Used': high_row['AI_Tool_Used'],
                        'Satisfaction_Level': high_row['Satisfaction_Level'],
                        'Education_Level': high_row['Education_Level'],
                        'City': high_row['City'],
                        'Gender': high_row['Gender'],
                        'Age': int(high_row['Age'])
                    },
                    'possible_explanatory_factors': differing_factors
                })

factor_columns = ['Education_Level', 'Purpose', 'AI_Tool_Used', 'Satisfaction_Level', 'Gender', 'City']
factor_summaries = {}

for col in factor_columns:
    cross = pd.crosstab(df[col], df['Impact_on_Grades'])
    factor_summaries[col] = cross.to_dict()

if pairs:
    result = {
        'similar_study_time_different_performance': pairs,
        'summary': (
            'Students with the same Daily_Usage_Hours can still report very different grade impacts. '
            'The most plausible factors in this dataset are differences in Purpose, Satisfaction_Level, '
            'AI_Tool_Used, and Education_Level, with demographic/context variables like Age, City, and Gender '
            'also varying across matched pairs.'
        ),
        'factor_distributions_by_grade_impact': factor_summaries
    }
else:
    # fallback: use nearest study-time pairs within 0.2 hours and large impact differences
    df1 = df.reset_index(drop=True)
    fallback_pairs = []
    for i in range(len(df1)):
        for j in range(i + 1, len(df1)):
            if abs(df1.loc[i, 'Daily_Usage_Hours'] - df1.loc[j, 'Daily_Usage_Hours']) <= 0.2:
                score_diff = abs(df1.loc[i, 'Impact_Score'] - df1.loc[j, 'Impact_Score'])
                if pd.notna(score_diff) and score_diff >= 2:
                    a = df1.loc[i]
                    b = df1.loc[j]
                    differing_factors = {}
                    for col in ['Education_Level', 'Purpose', 'AI_Tool_Used', 'Satisfaction_Level', 'Gender', 'City', 'Age']:
                        if a[col] != b[col]:
                            differing_factors[col] = [a[col], b[col]]
                    fallback_pairs.append({
                        'student_1': {
                            'Student_ID': int(a['Student_ID']),
                            'Daily_Usage_Hours': float(a['Daily_Usage_Hours']),
                            'Impact_on_Grades': a['Impact_on_Grades']
                        },
                        'student_2': {
                            'Student_ID': int(b['Student_ID']),
                            'Daily_Usage_Hours': float(b['Daily_Usage_Hours']),
                            'Impact_on_Grades': b['Impact_on_Grades']
                        },
                        'possible_explanatory_factors': differing_factors
                    })
    result = {
        'similar_study_time_different_performance': fallback_pairs,
        'summary': (
            'Using a relaxed definition of similar study time (within 0.2 hours), some students show notably '
            'different academic outcomes. Likely explanations include differences in study purpose, satisfaction '
            'with AI use, tool choice, and education level.'
        ),
        'factor_distributions_by_grade_impact': factor_summaries
    }

import pandas as pd
import numpy as np

df = pd.read_csv('AI_Student_Life_Pakistan_2026.csv')

low_usage_threshold = df['Daily_Usage_Hours'].quantile(0.25)

high_stress_mask = (
    df['Satisfaction_Level'].astype(str).str.strip().str.lower().eq('low')
)

low_study_mask = df['Daily_Usage_Hours'] <= low_usage_threshold

target = df.loc[high_stress_mask & low_study_mask].copy()

factors = {}
if not target.empty:
    factors = {
        'education_level_distribution': target['Education_Level'].value_counts().to_dict(),
        'city_distribution': target['City'].value_counts().to_dict(),
        'gender_distribution': target['Gender'].value_counts().to_dict(),
        'ai_tool_used_distribution': target['AI_Tool_Used'].value_counts().to_dict(),
        'purpose_distribution': target['Purpose'].value_counts().to_dict(),
        'impact_on_grades_distribution': target['Impact_on_Grades'].value_counts().to_dict(),
        'average_age': float(target['Age'].mean()),
        'average_daily_usage_hours': float(target['Daily_Usage_Hours'].mean())
    }

students = target[
    [
        'Student_ID', 'Age', 'Gender', 'Education_Level', 'City',
        'AI_Tool_Used', 'Daily_Usage_Hours', 'Purpose',
        'Impact_on_Grades', 'Satisfaction_Level'
    ]
].to_dict(orient='records')

possible_explanations = []
if not target.empty:
    if factors['impact_on_grades_distribution']:
        possible_explanations.append(
            "Low satisfaction among low-usage students may be linked to weaker academic outcomes, especially where grades show 'No Change' or 'Slight Decline'."
        )
    if factors['purpose_distribution']:
        possible_explanations.append(
            "Their main usage purpose may matter: students using AI mainly for writing, research, or learning may still feel pressure if those tasks remain difficult despite limited usage time."
        )
    if factors['education_level_distribution']:
        possible_explanations.append(
            "Education level could play a role, as school/college/university demands differ and some groups may face more pressure even with relatively low usage hours."
        )
    if factors['city_distribution']:
        possible_explanations.append(
            "City-level concentration may hint at environmental or institutional differences affecting student pressure and satisfaction."
        )
    possible_explanations.append(
        "Because the dataset has no direct stress column, 'low satisfaction' is used as a proxy for high stress, so explanations are indicative rather than definitive."
    )

result = {
    'low_usage_threshold_daily_hours': float(low_usage_threshold),
    'students_with_high_stress_proxy_and_low_study_hours': students,
    'count': int(len(target)),
    'possible_factors': factors,
    'interpretation': possible_explanations
}

import pandas as pd
import numpy as np

df = pd.read_csv('AI_Student_Life_Pakistan_2026.csv')

impact_map = {
    'Significant Decline': 1,
    'Slight Decline': 2,
    'No Change': 3,
    'Improved': 4,
    'Significantly Improved': 5
}

df = df.copy()
df['Impact_Score'] = df['Impact_on_Grades'].map(impact_map)

pairs = []
n = len(df)

for i in range(n):
    for j in range(i + 1, n):
        time_diff = abs(df.loc[i, 'Daily_Usage_Hours'] - df.loc[j, 'Daily_Usage_Hours'])
        score_diff = abs(df.loc[i, 'Impact_Score'] - df.loc[j, 'Impact_Score'])
        if time_diff <= 0.3 and score_diff >= 2:
            row_i = df.loc[i]
            row_j = df.loc[j]
            differing_factors = []
            for col in ['Purpose', 'AI_Tool_Used', 'Satisfaction_Level', 'Education_Level', 'Gender', 'City', 'Age']:
                if row_i[col] != row_j[col]:
                    differing_factors.append(col)
            pairs.append({
                'Student_1_ID': int(row_i['Student_ID']),
                'Student_2_ID': int(row_j['Student_ID']),
                'Student_1_Study_Time': float(row_i['Daily_Usage_Hours']),
                'Student_2_Study_Time': float(row_j['Daily_Usage_Hours']),
                'Student_1_Performance': row_i['Impact_on_Grades'],
                'Student_2_Performance': row_j['Impact_on_Grades'],
                'Study_Time_Difference': float(round(time_diff, 3)),
                'Performance_Gap_Score': int(score_diff),
                'Potential_Explaining_Factors': differing_factors
            })

pairs_sorted = sorted(
    pairs,
    key=lambda x: (x['Study_Time_Difference'], -x['Performance_Gap_Score'], x['Student_1_ID'], x['Student_2_ID'])
)

factor_counts = {}
for p in pairs_sorted:
    for f in p['Potential_Explaining_Factors']:
        factor_counts[f] = factor_counts.get(f, 0) + 1

result = {
    'criteria_used': {
        'similar_study_time_max_difference_hours': 0.3,
        'significant_performance_difference_min_score_gap': 2,
        'performance_scale': impact_map
    },
    'matching_student_pairs_count': len(pairs_sorted),
    'student_pairs': pairs_sorted,
    'most_common_potential_factors': dict(sorted(factor_counts.items(), key=lambda x: (-x[1], x[0]))),
    'summary': (
        'Students were matched when their Daily_Usage_Hours were within 0.3 hours but their '
        'Impact_on_Grades differed by at least two levels. Possible explanations were inferred '
        'from differences in Purpose, AI_Tool_Used, Satisfaction_Level, Education_Level, Gender, '
        'City, and Age between each matched pair.'
    )
}

import pandas as pd

df = pd.read_csv('AI_Student_Life_Pakistan_2026.csv')

avg_usage_by_city = (
    df.groupby('City', as_index=False)['Daily_Usage_Hours']
    .mean()
    .sort_values('Daily_Usage_Hours', ascending=False)
)

max_avg = avg_usage_by_city['Daily_Usage_Hours'].max()
top_cities = avg_usage_by_city[avg_usage_by_city['Daily_Usage_Hours'] == max_avg]

result = {
    "highest_average_daily_ai_usage_hours": float(max_avg),
    "cities": top_cities['City'].tolist(),
    "city_averages": [
        {"City": row["City"], "Average_Daily_Usage_Hours": float(row["Daily_Usage_Hours"])}
        for _, row in avg_usage_by_city.iterrows()
    ]
}

import pandas as pd
import numpy as np

df = pd.read_csv('AI_Student_Life_Pakistan_2026.csv')

impact_order = {
    'Significant Decline': 0,
    'Slight Decline': 1,
    'No Change': 2,
    'Improved': 3,
    'Significant Improvement': 4
}

df = df.copy()
df['Impact_Score'] = df['Impact_on_Grades'].map(impact_order)

# Group students by similar study/use time using rounded usage buckets
df['Usage_Bucket'] = df['Daily_Usage_Hours'].round(1)

pairs = []
for bucket, g in df.groupby('Usage_Bucket'):
    g = g.sort_values('Impact_Score')
    min_score = g['Impact_Score'].min()
    max_score = g['Impact_Score'].max()
    if pd.notna(min_score) and pd.notna(max_score) and (max_score - min_score) >= 2:
        low_group = g[g['Impact_Score'] == min_score]
        high_group = g[g['Impact_Score'] == max_score]
        for _, low in low_group.iterrows():
            for _, high in high_group.iterrows():
                differing_factors = {}
                for col in ['Purpose', 'Satisfaction_Level', 'AI_Tool_Used', 'Education_Level', 'City', 'Gender', 'Age']:
                    if low[col] != high[col]:
                        differing_factors[col] = {
                            'lower_performance_student': low[col],
                            'higher_performance_student': high[col]
                        }
                pairs.append({
                    'Daily_Usage_Hours': float(bucket),
                    'lower_performance_student': {
                        'Student_ID': int(low['Student_ID']),
                        'Impact_on_Grades': low['Impact_on_Grades']
                    },
                    'higher_performance_student': {
                        'Student_ID': int(high['Student_ID']),
                        'Impact_on_Grades': high['Impact_on_Grades']
                    },
                    'possible_explanatory_factors': differing_factors
                })

# Keep a manageable set of strongest examples
pairs_sorted = sorted(
    pairs,
    key=lambda x: (
        impact_order[x['higher_performance_student']['Impact_on_Grades']] -
        impact_order[x['lower_performance_student']['Impact_on_Grades']]
    ),
    reverse=True
)

summary_factors = {}
for p in pairs_sorted:
    for factor in p['possible_explanatory_factors']:
        summary_factors[factor] = summary_factors.get(factor, 0) + 1

result = {
    'similar_study_time_different_performance_examples': pairs_sorted[:10],
    'likely_factors_explaining_differences': sorted(
        [{'factor': k, 'count_across_examples': int(v)} for k, v in summary_factors.items()],
        key=lambda x: x['count_across_examples'],
        reverse=True
    ),
    'note': 'Students were compared within the same Daily_Usage_Hours bucket (rounded to 0.1 hour). Differences in purpose, satisfaction, tool used, education level, city, age, and gender may help explain why similar usage time is associated with different grade impact.'
}

import pandas as pd
import numpy as np

df = pd.read_csv('AI_Student_Life_Pakistan_2026.csv')

impact_order = {
    'Significant Decline': 0,
    'Slight Decline': 1,
    'No Change': 2,
    'Improved': 3,
    'Significantly Improved': 4
}

df = df.copy()
df['Impact_Score'] = df['Impact_on_Grades'].map(impact_order)

pairs = []
tolerance = 0.2
min_diff = 2

for i in range(len(df)):
    for j in range(i + 1, len(df)):
        h1 = df.iloc[i]['Daily_Usage_Hours']
        h2 = df.iloc[j]['Daily_Usage_Hours']
        s1 = df.iloc[i]['Impact_Score']
        s2 = df.iloc[j]['Impact_Score']
        if pd.notna(s1) and pd.notna(s2):
            if abs(h1 - h2) <= tolerance and abs(s1 - s2) >= min_diff:
                row1 = df.iloc[i]
                row2 = df.iloc[j]
                differing_factors = {}
                for col in ['Education_Level', 'Purpose', 'AI_Tool_Used', 'Satisfaction_Level', 'Gender', 'City', 'Age']:
                    if row1[col] != row2[col]:
                        differing_factors[col] = [row1[col], row2[col]]
                pairs.append({
                    'Student_1_ID': int(row1['Student_ID']),
                    'Student_2_ID': int(row2['Student_ID']),
                    'Student_1_Usage_Hours': float(row1['Daily_Usage_Hours']),
                    'Student_2_Usage_Hours': float(row2['Daily_Usage_Hours']),
                    'Student_1_Impact': row1['Impact_on_Grades'],
                    'Student_2_Impact': row2['Impact_on_Grades'],
                    'Usage_Difference_Hours': float(abs(h1 - h2)),
                    'Impact_Score_Difference': int(abs(s1 - s2)),
                    'Potential_Explaining_Factors': differing_factors
                })

pairs_sorted = sorted(
    pairs,
    key=lambda x: (-x['Impact_Score_Difference'], x['Usage_Difference_Hours'], x['Student_1_ID'], x['Student_2_ID'])
)

top_pairs = pairs_sorted[:10]

factor_counts = {}
for p in pairs:
    for factor in p['Potential_Explaining_Factors'].keys():
        factor_counts[factor] = factor_counts.get(factor, 0) + 1

factor_counts = dict(sorted(factor_counts.items(), key=lambda x: (-x[1], x[0])))

result = {
    'similar_study_time_different_performance_pairs': top_pairs,
    'summary': {
        'pair_count_found': int(len(pairs)),
        'study_time_similarity_threshold_hours': tolerance,
        'minimum_performance_gap_on_ordinal_scale': min_diff,
        'most_common_potential_factors': factor_counts
    },
    'interpretation': (
        "Students with nearly the same daily AI study/usage time can still report very different grade impacts. "
        "In this dataset, the biggest observable factors associated with these differences are variations in "
        "Purpose, Satisfaction_Level, Education_Level, AI_Tool_Used, Age, City, and Gender across matched pairs. "
        "This suggests that how students use AI, how satisfied they are with it, and their academic context may matter "
        "more than time spent alone."
    )
}

import pandas as pd

df = pd.read_csv(csv_path)
avg_by_city = df.groupby("City", as_index=False)["Daily_Usage_Hours"].mean()
max_avg = avg_by_city["Daily_Usage_Hours"].max()
top_cities = avg_by_city[avg_by_city["Daily_Usage_Hours"] == max_avg].copy()
top_cities = top_cities.sort_values(["Daily_Usage_Hours", "City"], ascending=[False, True])

result = {
    "highest_average_daily_ai_usage_hours": float(max_avg),
    "cities": top_cities["City"].tolist(),
    "details": [
        {
            "City": row["City"],
            "Average_Daily_Usage_Hours": float(row["Daily_Usage_Hours"])
        }
        for _, row in top_cities.iterrows()
    ]
}

